const TreeNode: React.FC<{ node: IANode; depth?: number }> = ({ node, depth = 0 }) => {
  const [isOpen, setIsOpen] = useState(true);
  const hasChildren = node.children && node.children.length > 0;

  return (
    <div className={`ml-4 border-l border-gray-200 pl-4 py-1 ${depth === 0 ? 'print:ml-0 print:border-none print:pl-0' : ''}`}>
      <div 
        className={`flex items-start gap-2 group cursor-pointer ${hasChildren ? 'hover:bg-gray-50' : ''} p-2 rounded-lg transition-colors print:cursor-default print:hover:bg-transparent`}
        onClick={() => !window.matchMedia('print').matches && setIsOpen(!isOpen)}
      >
        {hasChildren ? (
          isOpen ? <ChevronDown className="w-4 h-4 mt-1 text-blue-500 print:hidden" /> : <ChevronRight className="w-4 h-4 mt-1 text-blue-500 print:hidden" />
        ) : (
          <div className="w-4 h-4 mt-1 flex items-center justify-center">
            <div className="w-1.5 h-1.5 rounded-full bg-gray-400" />
          </div>
        )}
        <div className="hidden print:block w-4 h-4 mt-1 flex items-center justify-center">
          <div className="w-2 h-2 rounded-sm border border-blue-400" />
        </div>
        <div>
          <span className={`font-medium ${depth === 0 ? 'text-blue-700 text-lg' : 'text-gray-700'}`}>
            {node.label}
          </span>
          {node.description && (
            <p className="text-sm text-gray-500 italic mt-0.5">{node.description}</p>
          )}
        </div>
      </div>
      {hasChildren && (isOpen || window.matchMedia('print').matches) && (
        <div className="mt-1">
          {node.children?.map((child, idx) => (
            <TreeNode key={idx} node={child} depth={depth + 1} />
          ))}
        </div>
      )}
    </div>
  );
};

