      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">

        {/* Navegación Móvil (No se imprime) */}
        <div className="flex lg:hidden bg-white p-1 rounded-xl shadow-sm mb-6 overflow-x-auto no-scrollbar no-print">
          {['decision', 'ia', 'metodo', 'insights'].map((tab) => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`flex-1 whitespace-nowrap px-4 py-2 rounded-lg text-sm font-medium transition-all ${activeTab === tab ? 'bg-blue-600 text-white shadow-md' : 'text-gray-600'}`}
            >
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>

        {/* CONTENIDO DE LAS SECCIONES */}

        {/* 1. METODOLOGÍA (Página 1 PDF) */}
        <div className={`${activeTab === 'metodo' ? 'block' : 'hidden print:block'} section-to-print animate-in fade-in zoom-in-95 duration-500`}>
          <section className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8 card">
            <div className="flex items-center gap-3 mb-8">
              <div className="p-3 bg-blue-100 rounded-xl no-print">
                <GitBranch className="w-8 h-8 text-blue-600" />
              </div>
              <div>
                <h2 className="text-3xl font-bold text-gray-900">1. Metodología: Doble Diamante (MVP)</h2>
                <p className="text-gray-500">Plan de ejecución para despliegue rápido e iteración remota.</p>
              </div>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
              {METHODOLOGY_STEPS.map((step) => (
                <div key={step.id} className="p-6 rounded-2xl border border-gray-100 bg-gray-50 shadow-sm relative overflow-hidden group hover:border-blue-500 transition-all card">
                  <div className={`inline-flex p-3 rounded-xl mb-4 ${step.color} shadow-sm`}>
                    {step.icon}
                  </div>
                  <h3 className="font-extrabold text-gray-900 mb-2">{step.title}</h3>
                  <p className="text-xs text-gray-600 leading-relaxed font-medium">{step.description}</p>
                </div>
              ))}
            </div>

            <div className="bg-slate-900 text-white p-10 rounded-3xl border-l-8 border-blue-500 shadow-xl print:bg-gray-100 print:text-black print:border-blue-600">
              <div className="flex items-center gap-4 mb-6">
                <BarChart3 className="w-8 h-8 text-blue-400 print:text-blue-700" />
                <h3 className="text-2xl font-bold italic">Justificación del Enfoque Remoto</h3>
              </div>
              <div className="grid md:grid-cols-2 gap-10">
                <p className="text-base text-slate-300 leading-relaxed print:text-gray-800">
                  Ante la imposibilidad de research presencial, el **Doble Diamante** nos permite converger rápidamente en un MVP funcional. Este producto actuará como nuestra "unidad de exploración" en el mercado.
                </p>
                <p className="text-base text-slate-300 leading-relaxed print:text-gray-800">
                  La etapa de "Entregar" no es el final, sino el inicio de la **investigación cuantitativa continua**. Cada interacción en el sitio se convierte en un dato para la siguiente fase.
                </p>
              </div>
            </div>
          </section>
        </div>

        {/* 2. DECISIÓN Y OBJETIVOS (Página 2 PDF) - ESTA ES LA SECCIÓN QUE ME PEDISTE */}
        <div className={`${activeTab === 'decision' ? 'block' : 'hidden print:block'} section-to-print animate-in fade-in duration-500`}>
          <section className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden card">
            <div className="p-8">
              <div className="flex items-center gap-3 mb-8">
                <div className="p-3 bg-blue-100 rounded-xl no-print">
                  <TrendingUp className="w-8 h-8 text-blue-600" />
                </div>
                <h2 className="text-3xl font-bold text-gray-900">2. Estrategia de Producto: Catálogo vs Tienda</h2>
              </div>

              <div className="grid md:grid-cols-2 gap-8 mb-12">
                <div className="border border-gray-200 rounded-2xl p-8 bg-gray-50 opacity-50 relative card">
                  <div className="flex items-center gap-3 mb-6 text-gray-400">
                    <ShoppingCart className="w-7 h-7" />
                    <h3 className="font-black text-xl uppercase tracking-widest">Tienda Online</h3>
                  </div>
                  <ul className="space-y-4">
                    <li className="flex items-center gap-3 text-sm text-gray-500 font-medium italic">
                      <AlertCircle className="w-5 h-5 text-amber-400 flex-shrink-0" />
                      Inviable: Precios variables por medidas personalizadas.
                    </li>
                  </ul>
                </div>

                <div className="border-4 border-blue-600 rounded-2xl p-8 bg-blue-50 relative shadow-2xl card">
                  <div className="absolute -top-4 right-6 bg-blue-600 text-white text-xs font-black px-4 py-2 rounded-full uppercase tracking-tighter no-print">
                    RECOMENDACIÓN GANADORA
                  </div>
                  <div className="flex items-center gap-3 mb-6 text-blue-800">
                    <Library className="w-7 h-7" />
                    <h3 className="font-black text-xl uppercase tracking-widest">Catálogo + Cotizador</h3>
                  </div>
                  <ul className="space-y-4">
                    <li className="flex items-center gap-3 text-base text-blue-900 font-bold">
                      <CheckCircle2 className="w-6 h-6 text-green-500 flex-shrink-0" />
                      Captura intención real y datos de m².
                    </li>
                    <li className="flex items-center gap-3 text-base text-blue-900 font-bold">
                      <CheckCircle2 className="w-6 h-6 text-green-500 flex-shrink-0" />
                      Reduce la fricción de cotización manual.
                    </li>
                  </ul>
                </div>
              </div>

              {/* SECCIÓN RESTAURADA CON LOS RECUADROS QUE ME SEÑALASTE */}
              <div className="mt-12 border-t-2 border-gray-100 pt-10">
                <h3 className="text-2xl font-black text-gray-900 mb-8 flex items-center gap-3 uppercase tracking-tight">
                  <Target className="w-7 h-7 text-blue-600" />
                  Impacto en Objetivos de Negocio
                </h3>
                <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {BUSINESS_GOALS.map((goal) => (
                    <div key={goal.id} className="bg-white p-6 rounded-2xl border-2 border-gray-50 shadow-sm hover:border-blue-200 hover:shadow-xl transition-all card">
                      <div className="text-blue-600 mb-4 bg-blue-50 w-12 h-12 rounded-xl flex items-center justify-center">{goal.icon}</div>
                      <h4 className="font-black text-gray-900 mb-2 text-sm uppercase">Pilar {goal.id}</h4>
                      <p className="text-xs text-gray-500 leading-relaxed font-semibold">{goal.text}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </section>
        </div>

        {/* 3. ARQUITECTURA IA (Página 3 PDF) */}
        <div className={`${activeTab === 'ia' ? 'block' : 'hidden print:block'} section-to-print animate-in slide-in-from-bottom-4 duration-500`}>
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-10 card">
            <h2 className="text-3xl font-bold text-gray-900 mb-10">3. Arquitectura de Información (IA Map)</h2>
            <div className="bg-blue-50/50 rounded-3xl p-10 border-2 border-dashed border-blue-200 print:border-none print:bg-transparent print:p-0">
              <TreeNode node={INFORMATION_ARCHITECTURE} />
            </div>
          </div>
        </div>

        {/* 4. INSIGHTS Y KPIs (Página 4 PDF) */}
        <div className={`${activeTab === 'insights' ? 'block' : 'hidden print:block'} section-to-print grid md:grid-cols-2 gap-10 animate-in zoom-in-95 duration-500`}>
          <div className="space-y-8">
            <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-3">
              <FileText className="w-7 h-7 text-blue-600" />
