            </h3>
            {ACTIONABLE_INSIGHTS.map((insight, idx) => (
              <div key={idx} className="bg-white p-8 rounded-2xl border border-gray-100 shadow-md relative group card">
                <div className={`absolute top-0 left-0 bottom-0 w-2 rounded-l-2xl ${insight.type === 'actionable' ? 'bg-green-500' : 'bg-blue-600'} print:hidden`} />
                <h4 className="font-black text-gray-900 mb-3 text-lg">{insight.title}</h4>
                <p className="text-sm text-gray-600 leading-relaxed font-medium">{insight.description}</p>
              </div>
            ))}
          </div>

          <div className="space-y-8">
            <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-3">
              <Share2 className="w-7 h-7 text-blue-600" />
              Métricas de Éxito (KPIs)
            </h3>
            <div className="bg-white p-10 rounded-3xl border-2 border-blue-100 shadow-2xl card">
              <h4 className="text-xl font-black mb-6 text-blue-800 uppercase tracking-widest">Plan de Medición MVP</h4>
              <ul className="space-y-6">
                {[
                  { n: 1, t: "Conversión de Cotizador", d: "Porcentaje de usuarios que terminan el flujo de m² y saltan a WhatsApp." },
                  { n: 2, t: "Popularidad de Catálogo", d: "Categoría con más interacciones (Ventanas vs Puertas vs Mantenimiento)." },
                  { n: 3, t: "Retención Remota", d: "Frecuencia de retorno de usuarios detectados en la localidad objetivo." }
                ].map((kpi) => (
                  <li key={kpi.n} className="flex items-start gap-5">
                    <div className="w-8 h-8 rounded-xl bg-blue-600 text-white flex items-center justify-center text-sm font-black shadow-lg flex-shrink-0">{kpi.n}</div>
                    <div>
                      <h5 className="font-bold text-gray-900 text-base">{kpi.t}</h5>
                      <p className="text-sm text-gray-500 font-medium">{kpi.d}</p>
                    </div>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </div>

      </main>

      {/* Botón de Exportación Fijo (No se imprime) */}
      <footer className="bg-white border-t border-gray-200 py-6 sticky bottom-0 z-40 no-print">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-4 text-xs font-bold text-gray-500 uppercase tracking-widest">
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse" />
              Metodología Activa
            </div>
            <div className="hidden sm:block text-gray-300">|</div>
            <div className="flex items-center gap-2">
              <BarChart3 className="w-5 h-5 text-blue-600" />
              Reporte de Datos Listo
            </div>
          </div>
          <button 
            onClick={handleDownload}
            disabled={isDownloading}
            className={`w-full sm:w-auto px-10 py-4 bg-blue-600 text-white font-black rounded-2xl shadow-2xl shadow-blue-200 hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-3 ${isDownloading ? 'opacity-80 cursor-not-allowed' : ''}`}
          >
            {isDownloading ? (
              <>
                <Loader2 className="w-6 h-6 animate-spin" />
                PREPARANDO PDF...
              </>
            ) : (
              <>
                <Download className="w-6 h-6" />
                DESCARGAR ESTRATEGIA EN PDF
              </>
            )}
          </button>
        </div>
      </footer>

      {/* Pie de página para el PDF */}
      <div className="print-only text-center text-sm font-bold text-gray-400 mt-20 pb-10 border-t pt-6">
        INFORME UX PARA METAL ALUMINIO FARCO - CONFIDENCIAL - {new Date().getFullYear()}
      </div>
    </div>
  );
};

export default App;
